mapper.select:
SELECT t.task_id, t.project_id, p.project_name, t.task_title, t.task_status, t.priority, t.assignee_user_id, t.start_date, t.due_date, t.progress_rate, m.milestone_name FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id LEFT JOIN schedule_milestone m ON m.milestone_id = t.milestone_id
AND t.project_id = #{project_id}
AND t.assignee_user_id = #{assignee_user_id}
AND t.task_status = #{task_status}
AND ( t.task_title ILIKE CONCAT('%', #{keyword}, '%') OR p.project_name ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY t.due_date NULLS LAST, t.task_id DESC
